# ── Pity ─────────────────────────────────────────────────────────────────────
PITY_THRESHOLD = 40

# ── Rate limiting ─────────────────────────────────────────────────────────────
RATE_LIMIT_LOG_CHANNEL_ID = {rate_log_str}
RATE_LIMIT_MAX    = 3
RATE_LIMIT_WINDOW = 1.5
